}

final class DeepLinkRouter: ObservableObject {
    static let shared = DeepLinkRouter()

    @Published var route: DeepLink?

    private init() {}

    @discardableResult
    func handle(url: URL) -> Bool {
        guard let deepLink = DeepLinkParser.parse(url: url) else { return false }
        DispatchQueue.main.async { [weak self] in
            self?.route = deepLink
        }
        return true
    }

    func clear() {
        route = nil
    }
}

enum DeepLinkParser {
    static func parse(url: URL) -> DeepLink? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        // Accept only your domain(s)
        guard let host = components.host?.lowercased(),
              host == "myapp.com" || host.hasSuffix(".myapp.com") else { return nil }

        let path = components.path.lowercased()

        // https://myapp.com/reset-password?token=abc123
        if path == "/reset-password" {
            let token = components.queryItems?.first(where: { $0.name.lowercased() == "token" })?.value
            guard let token, !token.isEmpty else { return nil }
            return .resetPassword(token: token)
        }

        return nil
    }
}

